const jiraFields = {
  canalSeguimiento: 'customfield_10040',
  fechaDiagnostico: 'customfield_10041',
  tierPropuesto: 'customfield_10042',
  agenteIa: 'customfield_10043',
  importeSetup: 'customfield_10044',
  numeroToque: 'customfield_10045',
  proximaAccion: 'customfield_10046',
  fechaVencimiento: 'customfield_10047',
  notas: 'customfield_10048',
  sentimiento: 'customfield_10049',
  resumenConversacion: 'customfield_10050',
  fechaUltimoContacto: 'customfield_10051',
  emailLead: 'customfield_10052',
  telefonoWhatsapp: 'customfield_10053',
  empresa: 'customfield_10054',
  nombreContacto: 'customfield_10055',
  gmailThreadId: 'customfield_10056',
  ultimoMessageIdProcesado: 'customfield_10057',
  errorTecnico: 'customfield_10058'
};

const config = {
  jiraBaseUrl: 'https://greenpc.atlassian.net',
  projectKey: 'REEMPLAZAR_PROJECT_KEY',
  adminEmail: 'REEMPLAZAR_ADMIN_EMAIL',
  openaiModel: 'o4-mini',
  whatsappMode: 'simulado',
  whatsappWebhookUrl: 'REEMPLAZAR_WHATSAPP_WEBHOOK_URL',
  timezone: 'Europe/Madrid',
  businessHours: {
    start: 9,
    end: 18,
    days: [1, 2, 3, 4, 5]
  },
  confidenceThreshold: {
    auto: 0.80,
    review: 0.60
  }
};

return items.map(item => ({ json: { ...item.json, jiraFields, config } }));

const base = $items('Config Jira + campos')[0].json;
const issues = $json.issues || [];
return issues.map(issue => ({ json: { ...base, issueKey: issue.key, issueId: issue.id, fields: issue.fields } }));

const f = $json.jiraFields;
const fields = $json.fields || {};
const currentTouch = fields[f.numeroToque]?.value || 'T1 pendiente';
const canal = fields[f.canalSeguimiento]?.value || 'Email';
const nombre = fields[f.nombreContacto] || 'Hola';
const herramienta = fields[f.agenteIa] || 'vuestros sistemas';
const email = fields[f.emailLead] || '';
const telefono = fields[f.telefonoWhatsapp] || '';

let action = null;
let nextTouch = null;
let nextDueDays = null;
let sendChannel = canal;

if (currentTouch === 'Sin toque' || currentTouch === 'T1 pendiente' || !currentTouch) {
  action = 'send_touch_1';
  nextTouch = 'T1 enviado';
  nextDueDays = 5;
  sendChannel = canal;
} else if (currentTouch === 'T1 enviado' || currentTouch === 'T2 pendiente') {
  action = 'send_touch_2';
  nextTouch = 'T2 enviado';
  nextDueDays = 10;
  sendChannel = canal;
} else if (currentTouch === 'T2 enviado' || currentTouch === 'T3 pendiente') {
  action = 'send_touch_3';
  nextTouch = 'T3 enviado';
  nextDueDays = 3;
  sendChannel = 'WhatsApp';
} else if (currentTouch === 'T3 enviado' || currentTouch === 'Cierre pendiente') {
  action = 'close_no_response';
  nextTouch = 'Cerrado por silencio';
  nextDueDays = null;
  sendChannel = null;
} else {
  action = 'skip';
}

const due = new Date();
if (nextDueDays !== null) due.setDate(due.getDate() + nextDueDays);
const nextDueDate = nextDueDays !== null ? due.toISOString().slice(0, 10) : null;

let subject = '';
let body = '';

if (action === 'send_touch_1') {
  subject = `¿Has podido revisar la propuesta, ${nombre}?`;
  body = `Hola ${nombre},

Te escribo para saber si has podido revisar la propuesta que te enviamos tras la sesión con José Luis.

Si tienes cualquier duda sobre la solución, los plazos o algún otro punto, dime y lo vemos sin problema. Y si os viene bien una llamada rápida con el equipo técnico para que os expliquen cómo quedaría exactamente en vuestro caso, también la organizo encantado.

Un saludo,
Alberto · Myutopia`;
}

if (action === 'send_touch_2') {
  subject = `Una idea para ayudarte a decidir, ${nombre}`;
  body = `Hola ${nombre},

Quería retomar el contacto por si os ha surgido alguna duda sobre la propuesta.

A veces, lo que más ayuda antes de tomar la decisión es una llamada de 20 minutos con nuestros developers, para que os expliquen exactamente cómo se integraría el agente con ${herramienta}. Sin compromiso, solo para que lo veáis claro.

Si te viene bien, dime y lo agendo esta misma semana.

Un saludo,
Alberto · Myutopia`;
}

if (action === 'send_touch_3') {
  body = `Hola ${nombre}, último mensaje de mi parte para no saturarte 🙂

¿Seguís evaluando la propuesta o lo habéis aparcado por ahora?

Sin ningún problema en cualquier caso. Si no es el momento, lo entiendo perfectamente y lo retomamos cuando tenga sentido para vosotros. Solo quería cerrar el seguimiento por mi parte y no dejarte el tema en el aire.`;
}

let route = 'skip';
if (action === 'close_no_response') route = 'close';
else if (sendChannel === 'Email') route = 'email';
else if (sendChannel === 'WhatsApp' || sendChannel === 'Ambos') route = 'whatsapp';

return [{ json: { ...$json, currentTouch, touchAction: action, nextTouch, nextDueDate, sendChannel, route, touchSubject: subject, touchBody: body, leadEmail: email, telefonoWhatsapp: telefono, nombreContacto: nombre } }];

const f = $json.jiraFields;
const today = new Date().toISOString().slice(0, 10);
let nextAction = '';

if ($json.touchAction === 'send_touch_1') nextAction = 'Esperar respuesta tras Toque 1';
if ($json.touchAction === 'send_touch_2') nextAction = 'Esperar respuesta tras Toque 2';
if ($json.touchAction === 'send_touch_3') nextAction = 'Esperar respuesta tras Toque 3';
if ($json.touchAction === 'close_no_response') nextAction = 'Lead descartado automáticamente por falta de respuesta';

return [{
  json: {
    ...$json,
    jiraUpdatePayload: {
      fields: {
        [f.numeroToque]: { value: $json.nextTouch },
        [f.fechaVencimiento]: $json.nextDueDate,
        [f.fechaUltimoContacto]: today,
        [f.proximaAccion]: nextAction,
        [f.resumenConversacion]: `Última acción automática: ${$json.touchAction}`
      }
    }
  }
}];

const f = $json.jiraFields;
return [{
  json: {
    ...$json,
    jiraClosePayload: {
      fields: {
        [f.numeroToque]: { value: 'Cerrado por silencio' },
        [f.fechaVencimiento]: null,
        [f.proximaAccion]: 'Lead descartado automáticamente por falta de respuesta',
        [f.resumenConversacion]: 'Lead descartado automáticamente tras completar la secuencia de 3 toques sin respuesta.'
      }
    },
    closeCommentPayload: {
      body: {
        type: "doc",
        version: 1,
        content: [{ type: "paragraph", content: [{ type: "text", text: "Lead movido a Descartado por falta de respuesta tras 3 toques." }] }]
      }
    }
  }
}];

const base = $items('Construir cierre por silencio')[0].json;
const transitions = $json.transitions || [];
const transition = transitions.find(t => t.to && t.to.name === 'Descartado');
return [{ json: { ...base, transitionId: transition ? transition.id : null, transitionFound: Boolean(transition) } }];
